file.content:
.freedom-wall-page{
    width: 100%;
    padding: 0.8rem;
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.freedom-wall-header{
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 0.8rem;
    flex-wrap: wrap;
}

.freedom-wall-title-shell{
    display: flex;
    flex-direction: column;
    gap: 0.16rem;
}

.freedom-wall-title{
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.3rem;
    color: var(--text-heading);
}

.freedom-wall-subtitle{
    margin: 0;
    color: var(--text-faint);
    font-size: 0.78rem;
}

.freedom-wall-week-pill{
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    border-radius: 999px;
    padding: 0.35rem 0.75rem;
    font-size: 0.7rem;
    color: var(--text-secondary);
    font-weight: 600;
    letter-spacing: 0.01rem;
}

.freedom-wall-toolbar{
    display: flex;
    flex-direction: column;
    gap: 0.6rem;
    border: 1px solid var(--border-card);
    background: var(--bg-card);
    border-radius: 12px;
    padding: 0.7rem;
}

.freedom-wall-tool-group{
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.fw-tool-btn{
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    border-radius: 10px;
    padding: 0.4rem 0.72rem;
    font-size: 0.72rem;
    font-weight: 600;
    cursor: pointer;
}

.fw-tool-btn.is-active{
    border-color: var(--accent-sage);
    color: var(--accent-sage);
    background: color-mix(in srgb, var(--bg-secondary) 70%, var(--accent-sage) 8%);
}

.freedom-wall-tool-controls{
    display: flex;
    gap: 0.55rem;
    align-items: center;
    flex-wrap: wrap;
}

.freedom-wall-tool-controls input[type="text"],
.freedom-wall-tool-controls select{
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    border-radius: 8px;
    padding: 0.34rem 0.45rem;
    color: var(--text-secondary);
    font-size: 0.72rem;
    min-width: 150px;
}

.fw-label{
    color: var(--text-faint);
    font-size: 0.68rem;
    text-transform: uppercase;
    letter-spacing: 0.04rem;
    font-weight: 700;
}

.fw-stamp-grid{
    display: flex;
    gap: 0.4rem;
}

.fw-stamp-btn{
    width: 30px;
    height: 30px;
    border-radius: 8px;
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    cursor: pointer;
}

.fw-sticker-grid{
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

.fw-sticker-btn{
    width: 36px;
    height: 36px;
    font-size: 1.15rem;
}

.fw-stamp-btn.is-active{
    border-color: var(--accent-sage);
    background: color-mix(in srgb, var(--bg-secondary) 72%, var(--accent-sage) 8%);
}

.fw-readonly-pill{
    width: fit-content;
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    border-radius: 999px;
    padding: 0.28rem 0.7rem;
    font-size: 0.68rem;
    color: var(--text-faint);
    font-weight: 600;
}

.freedom-wall-note-editor{
    border: 1px solid var(--border-card);
    background: var(--bg-card);
    border-radius: 12px;
    padding: 0.7rem;
    display: flex;
    flex-direction: column;
    gap: 0.6rem;
}

.freedom-wall-note-editor h4{
    margin: 0;
    font-size: 0.9rem;
    color: var(--text-secondary);
}

.freedom-wall-note-editor textarea{
    min-height: 78px;
    border: 1px solid var(--border-card);
    border-radius: 8px;
    background: var(--bg-secondary);
    color: var(--text-secondary);
    padding: 0.4rem;
    resize: vertical;
}

.fw-note-controls{
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
    align-items: center;
}

.fw-note-controls label{
    font-size: 0.68rem;
    color: var(--text-faint);
    font-weight: 700;
}

.fw-note-controls select{
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    border-radius: 8px;
    padding: 0.32rem 0.4rem;
    font-size: 0.72rem;
}

.fw-note-actions,
.freedom-wall-selected-actions{
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.fw-apply-btn,
.fw-delete-btn{
    border-radius: 8px;
    padding: 0.38rem 0.68rem;
    font-size: 0.7rem;
    font-weight: 700;
    border: 1px solid var(--border-card);
    cursor: pointer;
}

.fw-apply-btn{
    background: color-mix(in srgb, var(--bg-secondary) 72%, var(--accent-sage) 12%);
    color: var(--accent-sage);
    border-color: color-mix(in srgb, var(--border-card) 70%, var(--accent-sage) 30%);
}

.fw-delete-btn{
    background: color-mix(in srgb, var(--bg-secondary) 72%, #ff4d6d 12%);
    color: #ff4d6d;
    border-color: color-mix(in srgb, var(--border-card) 70%, #ff4d6d 30%);
}

.freedom-wall-canvas-shell{
    position: relative;
    width: 100%;
    border: 1px solid var(--border-card);
    background: var(--bg-card);
    border-radius: 14px;
    padding: 6px;
    box-sizing: border-box;
    overflow: hidden;
    touch-action: none;
}

