    padding: 0.45rem 0.75rem;
    border-radius: 10px;
    background: color-mix(in srgb, var(--bg-card) 85%, #ff4d6d 15%);
    border: 1px solid color-mix(in srgb, var(--border-card) 60%, #ff4d6d 40%);
    color: #ff4d6d;
    font-size: 0.74rem;
    font-weight: 600;
}

.freedom-wall-footer{
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--text-faint);
    font-size: 0.7rem;
    font-weight: 600;
}

.fw-zoom-controls{
    position: absolute;
    bottom: 10px;
    right: 10px;
    display: flex;
    align-items: center;
    gap: 4px;
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 8px;
    padding: 3px 6px;
    z-index: 5;
    font-size: 0.7rem;
}

.fw-zoom-controls button{
    width: 26px;
    height: 26px;
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.82rem;
    color: var(--text-secondary);
    font-weight: 700;
}

.fw-zoom-level{
    min-width: 36px;
    text-align: center;
    color: var(--text-faint);
    font-weight: 600;
    font-variant-numeric: tabular-nums;
}

.fw-minimap{
    position: absolute;
    bottom: 10px;
    left: 10px;
    width: 100px;
    background: rgba(0, 0, 0, 0.06);
    border: 1px solid var(--border-card);
    border-radius: 6px;
    overflow: hidden;
    cursor: pointer;
    z-index: 5;
}

.fw-minimap-viewport{
    position: absolute;
    border: 2px solid var(--accent-sage);
    background: rgba(162, 28, 175, 0.08);
    border-radius: 2px;
    pointer-events: none;
}

