                                <StampNode
                                    item={{payload: draftStamp}}
                                    stageWidth={stageWidth}
                                    stageHeight={stageHeight}
                                    canEdit={true}
                                    isSelected={false}
                                    isDraft={true}
                                    onSelect={() => {}}
                                    onDragEnd={(event) => {
                                        const node = event?.target;
                                        if(!node) return;
                                        setDraftStamp((prev) => ({
                                            ...prev,
                                            x: clamp(node.x() / stageWidth, 0, 1),
                                            y: clamp(node.y() / stageHeight, 0, 1)
                                        }));
                                    }}
                                />
                            )}

                            {draftNote && (
                                <NoteNode
                                    item={{payload: draftNote}}
                                    stageWidth={stageWidth}
                                    stageHeight={stageHeight}
                                    canEdit={true}
                                    isSelected={false}
                                    isDraft={true}
                                    onSelect={() => {}}
                                    onDragEnd={(event) => {
                                        const node = event?.target;
                                        if(!node) return;
                                        setDraftNote((prev) => ({
                                            ...prev,
                                            x: clamp(node.x() / stageWidth, 0, 1),
                                            y: clamp(node.y() / stageHeight, 0, 1)
                                        }));
                                    }}
                                />
                            )}

                            {isDrawing && draftDoodlePoints.length >= 4 && (
                                <Line
                                    points={draftDoodlePoints.map((point, pointIndex) => (
                                        pointIndex % 2 === 0 ? point * stageWidth : point * stageHeight
                                    ))}
                                    stroke={doodleColor}
                                    strokeWidth={doodleSize}
                                    lineCap="round"
                                    lineJoin="round"
                                    tension={0.12}
                                />
                            )}

                            {placementPuffs.map((puff) => (
                                <PuffEffect key={puff.id} id={puff.id} x={puff.x} y={puff.y} onComplete={handlePuffComplete} />
                            ))}
                        </Layer>

                        <Layer listening={false}>
                            {remoteCursorItems.map((cursor) => (
                                <RemoteCursor key={cursor.clientId} cursor={cursor} stageWidth={stageWidth} stageHeight={stageHeight} />
                            ))}
                        </Layer>
                    </Stage>
                )}

                <div className="fw-zoom-controls">
                    <button type="button" onClick={handleZoomIn}>+</button>
                    {stageScale !== 1 && (
                        <span className="fw-zoom-level">{Math.round(stageScale * 100)}%</span>
                    )}
                    <button type="button" onClick={handleZoomOut}>&minus;</button>
                    {stageScale !== 1 && (
                        <button type="button" onClick={handleZoomReset}>Reset</button>
                    )}
                </div>

                {stageScale !== 1 && (() => {
                    const minimapWidth = 100;
                    const minimapHeight = Math.round(minimapWidth * (stageHeight / stageWidth));
                    const vpLeft = clamp((-stagePosition.x / stageScale) / stageWidth * minimapWidth, 0, minimapWidth);
                    const vpTop = clamp((-stagePosition.y / stageScale) / stageHeight * minimapHeight, 0, minimapHeight);
                    const vpWidth = clamp((1 / stageScale) * minimapWidth, 4, minimapWidth);
                    const vpHeight = clamp((1 / stageScale) * minimapHeight, 4, minimapHeight);

                    return (
                        <div
                            className="fw-minimap"
                            style={{ height: minimapHeight }}
                            onClick={(e) => {
                                const rect = e.currentTarget.getBoundingClientRect();
                                const clickX = (e.clientX - rect.left) / minimapWidth;
                                const clickY = (e.clientY - rect.top) / minimapHeight;
                                const newPos = clampStagePosition({
                                    x: -(clickX * stageWidth * stageScale - stageWidth / 2),
                                    y: -(clickY * stageHeight * stageScale - stageHeight / 2)
                                }, stageScale);
                                setStagePosition(newPos);
                            }}
                        >
                            <div
                                className="fw-minimap-viewport"
                                style={{
                                    left: vpLeft,
                                    top: vpTop,
                                    width: vpWidth,
                                    height: vpHeight
                                }}
                            />
                        </div>
                    );
                })()}
            </div>

            {wallError && (
                <div className="freedom-wall-error-toast">{wallError}</div>
            )}

            <div className="freedom-wall-footer">
                <span>{sortedItems.length} items this week</span>
                <span>
                    {createItemMutation.isPending || updateItemMutation.isPending || deleteItemMutation.isPending
                        ? "Syncing..."
                        : "Synced"}
                </span>
            </div>
        </div>
    );
};

