}

.fw-draft-note-row select{
    border: 1px solid var(--fw-cork-dark);
    background: rgba(255, 255, 255, 0.45);
    color: var(--fw-wood-trim);
    border-radius: 8px;
    padding: 0.3rem 0.4rem;
    font-size: 0.72rem;
}

.fw-draft-note-row input[type="color"]{
    width: 32px;
    height: 28px;
    border: 1px solid var(--fw-cork-dark);
    border-radius: 6px;
    padding: 0;
    cursor: pointer;
}

.fw-draft-note-row input[type="range"]{
    width: 80px;
}

.fw-draft-note-actions{
    display: flex;
    gap: 0.5rem;
}

.fw-draft-note-actions .fw-apply-btn:disabled{
    opacity: 0.45;
    cursor: not-allowed;
}

.freedom-wall-error-toast{
    padding: 0.45rem 0.75rem;
    border-radius: 10px;
    background: rgba(230, 57, 70, 0.15);
    border: 1px solid var(--fw-pin-red);
    color: var(--fw-pin-red);
    font-size: 0.74rem;
    font-weight: 600;
}

.freedom-wall-footer{
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--fw-cork-deep);
    font-size: 0.7rem;
    font-weight: 600;
}

.fw-zoom-controls{
    position: absolute;
    bottom: 10px;
    right: 10px;
    display: flex;
    align-items: center;
    gap: 4px;
    background: rgba(255, 255, 255, 0.55);
    backdrop-filter: blur(4px);
    border: 1px solid var(--fw-cork-dark);
