    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.3rem;
    color: var(--fw-chalk);
    text-shadow: 0 0 8px rgba(220, 225, 220, 0.15);
}

.freedom-wall-subtitle{
    margin: 0;
    color: var(--fw-chalk-dim);
    font-size: 0.78rem;
}

.freedom-wall-week-pill{
    border: 1px solid rgba(220, 225, 220, 0.15);
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(4px);
    border-radius: 999px;
    padding: 0.35rem 0.75rem;
    font-size: 0.7rem;
    color: var(--fw-chalk-dim);
    font-weight: 600;
    letter-spacing: 0.01rem;
}

.freedom-wall-toolbar{
    display: flex;
    flex-direction: column;
    gap: 0.6rem;
    border: 1px solid rgba(220, 225, 220, 0.1);
    background: rgba(0, 0, 0, 0.18);
    backdrop-filter: blur(6px);
    border-radius: 12px;
    padding: 0.7rem;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04), 0 2px 8px rgba(0, 0, 0, 0.2);
}

.freedom-wall-tool-group{
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.fw-tool-btn{
    border: 1px solid rgba(220, 225, 220, 0.15);
    background: rgba(255, 255, 255, 0.06);
    color: var(--fw-chalk-dim);
    border-radius: 10px;
    padding: 0.4rem 0.72rem;
    font-size: 0.72rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s, color 0.15s, border-color 0.15s, transform 0.1s;
}

.fw-tool-btn:hover{
    background: rgba(255, 255, 255, 0.1);
    color: var(--fw-chalk);
    transform: translateY(-1px);
}

.fw-tool-btn.is-active{
    border-color: var(--fw-chalk-yellow);
    color: var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.1);
    box-shadow: 0 0 8px rgba(245, 230, 163, 0.12);
    text-shadow: 0 0 6px rgba(245, 230, 163, 0.2);
}

.freedom-wall-tool-controls{
    display: flex;
    gap: 0.55rem;
    align-items: center;
    flex-wrap: wrap;
}

.freedom-wall-tool-controls input[type="text"],
.freedom-wall-tool-controls select{
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(0, 0, 0, 0.2);
    border-radius: 8px;
    padding: 0.34rem 0.45rem;
    color: var(--fw-chalk);
    font-size: 0.72rem;
    min-width: 150px;
}

.fw-label{
    color: var(--fw-chalk-faint);
    font-size: 0.68rem;
    text-transform: uppercase;
    letter-spacing: 0.04rem;
    font-weight: 700;
}

.fw-stamp-grid{
    display: flex;
    gap: 0.4rem;
}

.fw-stamp-btn{
    width: 30px;
    height: 30px;
    border-radius: 8px;
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(255, 255, 255, 0.06);
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
}

.fw-stamp-btn:hover{
    background: rgba(255, 255, 255, 0.12);
    transform: scale(1.08);
}

.fw-sticker-grid{
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

.fw-sticker-btn{
    width: 36px;
    height: 36px;
    font-size: 1.15rem;
}

.fw-stamp-btn.is-active{
    border-color: var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.1);
    box-shadow: 0 0 6px rgba(245, 230, 163, 0.12);
}

.fw-readonly-pill{
    width: fit-content;
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(0, 0, 0, 0.15);
    border-radius: 999px;
    padding: 0.28rem 0.7rem;
    font-size: 0.68rem;
    color: var(--fw-chalk-faint);
    font-weight: 600;
}

.freedom-wall-note-editor{
    border: 1px solid rgba(220, 225, 220, 0.1);
    background: rgba(0, 0, 0, 0.18);
    backdrop-filter: blur(6px);
    border-radius: 12px;
    padding: 0.7rem;
    display: flex;
    flex-direction: column;
    gap: 0.6rem;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04), 0 2px 8px rgba(0, 0, 0, 0.2);
}

.freedom-wall-note-editor h4{
    margin: 0;
    font-size: 0.9rem;
    color: var(--fw-chalk);
}

.freedom-wall-note-editor textarea{
    min-height: 78px;
    border: 1px solid rgba(220, 225, 220, 0.12);
    border-radius: 8px;
    background: rgba(0, 0, 0, 0.2);
    color: var(--fw-chalk);
    padding: 0.4rem;
    resize: vertical;
}

.fw-note-controls{
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
    align-items: center;
}

.fw-note-controls label{
    font-size: 0.68rem;
    color: var(--fw-chalk-faint);
    font-weight: 700;
}

.fw-note-controls select{
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(0, 0, 0, 0.2);
    color: var(--fw-chalk);
    border-radius: 8px;
    padding: 0.32rem 0.4rem;
    font-size: 0.72rem;
}

.fw-note-actions,
.freedom-wall-selected-actions{
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.fw-apply-btn,
.fw-delete-btn{
    border-radius: 8px;
    padding: 0.38rem 0.68rem;
    font-size: 0.7rem;
    font-weight: 700;
    border: 1px solid rgba(220, 225, 220, 0.12);
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
}

.fw-apply-btn{
    background: rgba(168, 230, 163, 0.12);
    color: var(--fw-chalk-green);
    border-color: rgba(168, 230, 163, 0.3);
    text-shadow: 0 0 6px rgba(168, 230, 163, 0.15);
}

.fw-apply-btn:hover{
    background: rgba(168, 230, 163, 0.2);
    transform: translateY(-1px);
}

.fw-delete-btn{
    background: rgba(242, 167, 179, 0.1);
    color: var(--fw-chalk-pink);
    border-color: rgba(242, 167, 179, 0.3);
    text-shadow: 0 0 6px rgba(242, 167, 179, 0.15);
}

.fw-delete-btn:hover{
    background: rgba(242, 167, 179, 0.2);
    transform: translateY(-1px);
}

.freedom-wall-canvas-shell{
    position: relative;
    width: 100%;
    border: 5px solid var(--fw-frame);
    background: var(--fw-board-dark);
    border-radius: 4px;
    padding: 6px;
    box-sizing: border-box;
    overflow: hidden;
    touch-action: none;
    box-shadow:
        inset 0 0 20px rgba(0, 0, 0, 0.2),
        0 4px 20px rgba(0, 0, 0, 0.35),
        0 1px 3px rgba(0, 0, 0, 0.15);
    /* Wood frame with groove */
    border-image:
        linear-gradient(
            135deg,
            #8b6240 0%,
            #a07850 15%,
            #6b4226 30%,
            #7a5030 50%,
            #5c3a1e 70%,
            #8b6240 85%,
            #6b4226 100%
        ) 1;
}

.freedom-wall-loading,
.freedom-wall-error{
    padding: 2rem;
    text-align: center;
    color: var(--fw-chalk-dim);
}

.fw-draft-note-panel{
    border: 1px solid rgba(220, 225, 220, 0.1);
    background: rgba(0, 0, 0, 0.18);
    backdrop-filter: blur(6px);
    border-radius: 12px;
    padding: 0.7rem;
    display: flex;
    flex-direction: column;
    gap: 0.6rem;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04), 0 2px 8px rgba(0, 0, 0, 0.2);
}

.fw-draft-note-header{
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.fw-draft-note-header h4{
    margin: 0;
    font-size: 0.9rem;
    color: var(--fw-chalk);
    font-family: "Lexend Deca", sans-serif;
    text-shadow: 0 0 6px rgba(220, 225, 220, 0.1);
}

.fw-draft-note-charcount{
    font-size: 0.68rem;
    color: var(--fw-chalk-faint);
    font-weight: 600;
    font-variant-numeric: tabular-nums;
}

.fw-draft-note-textarea{
    width: 100%;
    min-height: 56px;
    border: 1px solid rgba(220, 225, 220, 0.12);
    border-radius: 8px;
    background: rgba(0, 0, 0, 0.2);
    color: var(--fw-chalk);
    padding: 0.45rem 0.55rem;
    font-size: 0.82rem;
    resize: vertical;
    box-sizing: border-box;
}

.fw-draft-note-controls{
    display: flex;
    gap: 0.55rem;
    flex-wrap: wrap;
    align-items: center;
}

.fw-draft-note-row{
    display: flex;
    align-items: center;
    gap: 0.35rem;
}

.fw-draft-note-row label{
    font-size: 0.68rem;
    color: var(--fw-chalk-faint);
    font-weight: 700;
}

.fw-draft-note-row select{
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(0, 0, 0, 0.2);
    color: var(--fw-chalk);
    border-radius: 8px;
    padding: 0.3rem 0.4rem;
    font-size: 0.72rem;
}

.fw-draft-note-row input[type="color"]{
    width: 32px;
    height: 28px;
    border: 1px solid rgba(220, 225, 220, 0.15);
    border-radius: 6px;
    padding: 0;
    cursor: pointer;
    background: rgba(0, 0, 0, 0.2);
}

.fw-draft-note-row input[type="range"]{
    width: 80px;
}

.fw-draft-note-actions{
    display: flex;
    gap: 0.5rem;
}

.fw-draft-note-actions .fw-apply-btn:disabled{
    opacity: 0.35;
    cursor: not-allowed;
}

.freedom-wall-error-toast{
    padding: 0.45rem 0.75rem;
    border-radius: 10px;
    background: rgba(242, 167, 179, 0.12);
    border: 1px solid rgba(242, 167, 179, 0.3);
    color: var(--fw-chalk-pink);
    font-size: 0.74rem;
    font-weight: 600;
}

.freedom-wall-footer{
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--fw-chalk-faint);
    font-size: 0.7rem;
    font-weight: 600;
}

.fw-zoom-controls{
    position: absolute;
    bottom: 10px;
    right: 10px;
    display: flex;
    align-items: center;
    gap: 4px;
    background: rgba(0, 0, 0, 0.35);
    backdrop-filter: blur(4px);
    border: 1px solid rgba(220, 225, 220, 0.1);
    border-radius: 8px;
    padding: 3px 6px;
    z-index: 5;
    font-size: 0.7rem;
}

.fw-zoom-controls button{
    width: 26px;
    height: 26px;
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(255, 255, 255, 0.06);
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.82rem;
    color: var(--fw-chalk-dim);
    font-weight: 700;
    transition: background 0.15s, color 0.15s;
}

.fw-zoom-controls button:hover{
    background: rgba(255, 255, 255, 0.12);
    color: var(--fw-chalk);
}

.fw-zoom-level{
    min-width: 36px;
    text-align: center;
    color: var(--fw-chalk-faint);
    font-weight: 600;
    font-variant-numeric: tabular-nums;
}

.fw-minimap{
    position: absolute;
    bottom: 10px;
    left: 10px;
    width: 100px;
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(220, 225, 220, 0.1);
    border-radius: 6px;
    overflow: hidden;
    cursor: pointer;
    z-index: 5;
}

.fw-minimap-viewport{
    position: absolute;
    border: 2px solid var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.08);
    border-radius: 2px;
    pointer-events: none;
}

@media (max-width: 480px){
    .freedom-wall-page{
        padding: 0.5rem;
        padding-bottom: 5rem;
    }

    .freedom-wall-week-pill{
        width: 100%;
        border-radius: 10px;
    }

    .freedom-wall-tool-controls{
        flex-direction: column;
        align-items: flex-start;
    }

    .freedom-wall-tool-controls input[type="text"],
    .freedom-wall-tool-controls select{
        width: 100%;
    }

    .fw-draft-note-controls{
        flex-direction: column;
        align-items: flex-start;
    }
}

/* Chalk-style accent for range/color inputs */
.freedom-wall-page input[type="range"]{
    accent-color: var(--fw-chalk-yellow);
}

.freedom-wall-page input[type="color"]{
    border: 1px solid rgba(220, 225, 220, 0.15);
    border-radius: 6px;
}

