    --fw-chalk-blue: #a3c9f5;
    --fw-chalk-green: #a8e6a3;
    --fw-chalk-orange: #f5c896;

    width: 100%;
    padding: 0.8rem;
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;

    /* Dark green chalkboard background */
    background:
        radial-gradient(
            ellipse at 25% 15%,
            rgba(60, 90, 65, 0.3) 0%,
            transparent 55%
        ),
        radial-gradient(
            ellipse at 75% 80%,
            rgba(40, 70, 50, 0.25) 0%,
